#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-04-19
#
# MDX compile guard — exercises scripts/test-mdx-compile.mjs both ways:
# 1. Asserts every docs/site/content/docs/**/*.mdx compiles cleanly.
# 2. Asserts the counter-example fixture (tests/fixtures/nested-fence.mdx)
#    is REJECTED by the same checker.
#
# This dual-direction TDD safety net ensures the guard stays sharp:
# if step 1 starts passing on a broken file, OR step 2 starts succeeding
# on the deliberately-broken fixture, this test fails.
#
# Origin: PR #1401 — protects against the class of bug fixed in #1399
# (nested same-length code fences in skill SKILL.md sources).

set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
PROJECT_ROOT="$(cd "$SCRIPT_DIR/../.." && pwd)"
DOCS_SITE="$PROJECT_ROOT/docs/site"
SCRIPT="$DOCS_SITE/scripts/test-mdx-compile.mjs"
FIXTURE="$DOCS_SITE/tests/fixtures/nested-fence.mdx"

RED=$'\033[0;31m'
GREEN=$'\033[0;32m'
YELLOW=$'\033[1;33m'
NC=$'\033[0m'

PASS=0
FAIL=0

pass() { echo "  ${GREEN}✓${NC} $1"; PASS=$((PASS + 1)); }
fail() { echo "  ${RED}✗${NC} $1"; FAIL=$((FAIL + 1)); }

echo "════════════════════════════════════════════════════════════════"
echo "  MDX Compile Guard"
echo "════════════════════════════════════════════════════════════════"
echo ""

# Pre-flight: ensure the script and fixture exist
if [[ ! -f "$SCRIPT" ]]; then
  echo "  ${RED}✗${NC} Missing: $SCRIPT"
  exit 1
fi
if [[ ! -f "$FIXTURE" ]]; then
  echo "  ${RED}✗${NC} Missing: $FIXTURE"
  exit 1
fi

# Pre-flight: ensure docs/site has @mdx-js/mdx available (script needs it +
# remark-gfm). Strategy:
#   1. If already in node_modules → done.
#   2. Otherwise try npm install. On 401 (private @yonatan-hq/analytics token
#      not available in PR builds — same root cause as docs.yml's fallback),
#      swap analytics to the local stub and retry. Mirrors docs.yml's pattern
#      so the guard works on every PR even without the private token.
if [[ ! -d "$DOCS_SITE/node_modules/@mdx-js/mdx" ]]; then
  echo "  ${YELLOW}⚠${NC} @mdx-js/mdx not in docs/site/node_modules — installing"
  INSTALL_LOG=$(mktemp)
  trap 'rm -f "$INSTALL_LOG"' EXIT

  set +e
  (cd "$DOCS_SITE" && npm ci --no-audit --no-fund 2>&1) >"$INSTALL_LOG"
  npm_exit=$?
  set -e

  if [[ $npm_exit -ne 0 ]]; then
    if grep -qE "401 Unauthorized|E401|unauthenticated" "$INSTALL_LOG"; then
      echo "  ${YELLOW}⚠${NC} npm ci hit 401 on @yonatan-hq/analytics — swapping to local stub and regenerating lockfile"
      # Deterministic fallback: swap analytics to the local file: stub, drop
      # the bumped lockfile, regenerate with --package-lock-only, then npm ci.
      # Once analytics points at a file: path, no @yonatan-hq registry lookups
      # happen — the .npmrc auth requirement no longer applies and `npm
      # install` succeeds without NPM_TOKEN. `--ignore-scripts` skips
      # fumadocs-mdx's postinstall (which would fail at the lockfile-only
      # stage with no node_modules yet).
      #
      # PR #1426 noted that `npm install --package-lock-only` was tried and
      # failed — but only WITHOUT swapping analytics first. After the swap
      # there are no @yonatan-hq registry calls and regeneration succeeds.
      # The committed package-lock.stub.json was deleted alongside this
      # change because it trapped every dependabot bump (#1630).
      (cd "$DOCS_SITE" \
        && npm pkg set 'dependencies.@yonatan-hq/analytics=file:../stubs/analytics-stub' >/dev/null \
        && rm -f package-lock.json \
        && npm install --no-audit --no-fund --package-lock-only --ignore-scripts 2>&1 | tail -3 \
        && npm ci --no-audit --no-fund 2>&1 | tail -3) || {
        fail "stub-regen + npm ci failed in docs/site"
        exit 1
      }
    else
      tail -10 "$INSTALL_LOG"
      fail "npm install failed in docs/site (not auth-related — see log above)"
      exit 1
    fi
  fi
fi

# ─── Test 1: every published mdx must compile ───────────────────────
echo "▶ Test 1: docs/site/content/docs/**/*.mdx all compile cleanly"
echo "────────────────────────────────────────────────────────────────"
if (cd "$DOCS_SITE" && node "$SCRIPT" 2>&1); then
  pass "All published mdx files compile"
else
  fail "At least one published mdx file failed to compile"
fi
echo ""

# ─── Test 2: counter-example MUST fail ──────────────────────────────
echo "▶ Test 2: counter-example fixture is rejected"
echo "────────────────────────────────────────────────────────────────"
if (cd "$DOCS_SITE" && node "$SCRIPT" "$FIXTURE" >/dev/null 2>&1); then
  fail "Counter-example $(basename "$FIXTURE") was NOT rejected — guard is broken"
  echo "    The fixture is supposed to fail. If it now compiles, either"
  echo "    @mdx-js/mdx changed its parser behavior, or someone 'fixed' the fixture."
  echo "    Investigate before proceeding — do not silently update the fixture."
else
  pass "Counter-example correctly rejected by the guard"
fi
echo ""

# ─── Summary ─────────────────────────────────────────────────────────
echo "════════════════════════════════════════════════════════════════"
echo "  Total: $((PASS + FAIL))  |  Passed: ${GREEN}${PASS}${NC}  |  Failed: ${RED}${FAIL}${NC}"
echo "════════════════════════════════════════════════════════════════"

[[ $FAIL -eq 0 ]] || exit 1
exit 0
